                    dp[1][i][j] = Math.abs(i - top[j]);
                } else if (grid[i][j] == 'X') {
                    left = i;
                    top[j] = i;
                }
            }
        }
        int[] bot = new int[n];
        Arrays.fill(bot, n);
        for (int i = m-1; i>=0; i--) {
            int right = -1;
            for (int j = n-1; j>=0; j--) {
                if (grid[i][j] == 'O') {
                    dp[3][i][j] = Math.abs(j - right);
                    dp[2][i][j] = Math.abs(i - bot[j]);
                } else if (grid[i][j] == 'X') {
                    right = j;
                    bot[j] = i;
                }
            }
