class Info {
    int up = Integer.MAX_VALUE;
    int down = Integer.MAX_VALUE;
    int left = Integer.MAX_VALUE;
    int right = Integer.MAX_VALUE;
}

public class Matrix {
    public static List<List<Integer>> solution(char[][] grid, int[] target) {
        int m = grid.length, n = grid[0].length;
        Info[][] dp = new Info[m][n];
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                dp[i][j] = new Info();
            }
        }

        // init dp
        // top down
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                // top
                if(i == 0 || grid[i - 1][j] == 'X') {
                    dp[i][j].up = 1;
                } else {
                    dp[i][j].up = dp[i - 1][j].up + 1;
                }
                // left
                if(j == 0 || grid[i][j - 1] == 'X') {
                    dp[i][j].left = 1;
                } else {
                    dp[i][j].left = dp[i][j - 1].left + 1;
                }
            }
        }

        // bottom up
        for(int i = m - 1; i >= 0; i--) {
            for(int j = n - 1; j >= 0; j--) {
                // bottom
                if(i == m - 1 || grid[i + 1][j] == 'X') {
                    dp[i][j].down = 1;
                } else {
                    dp[i][j].down = dp[i + 1][j].down + 1;
                }
                // right
                if(j == n - 1 || grid[i][j + 1] == 'X') {
                    dp[i][j].right = 1;
                } else {
                    dp[i][j].right = dp[i][j + 1].right + 1;
                }
            }
        }

        List<List<Integer>> results = new ArrayList<>();
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                if(grid[i][j] == 'O') {
                    Info info = dp[i][j];
                    if(info.left == target[0] && info.up == target[1] && info.down == target[2] && info.right == target[3])
                        results.add(Arrays.asList(i, j));
                }
            }
        }

        return results;
    }

    public static void main(String[] args) {
        char[][] grid = {
            { 'O', 'E', 'E', 'E', 'X' },
            { 'E', 'O', 'X', 'X', 'X' },
            { 'E', 'E', 'E', 'E', 'E' },
            { 'X', 'E', 'O', 'E', 'E' },
            { 'X', 'E', 'X', 'E', 'X' }
        };
        System.out.println(solution(grid, new int[] {2, 2, 4, 1}));
    }
}
