    public class RobotLocationFinder {

    public static List<int[]> findMatchingRobots(char[][] locationMap, int[] query) {
        List<int[]> matchingRobots = new ArrayList<>();

        int rows = locationMap.length;
        int cols = locationMap[0].length;

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                if (locationMap[i][j] == 'O') {
                    int leftDist = j;
                    int topDist = i;
                    int bottomDist = rows - i - 1;
                    int rightDist = cols - j - 1;

                    if (leftDist == query[0] && topDist == query[1] && bottomDist == query[2] && rightDist == query[3]) {
                        matchingRobots.add(new int[]{i, j});
                    }
                }
            }
        }

        return matchingRobots;
    }

